#!/usr/bin/env node

const { spawn } = require("child_process");
const path = require("path");

// Parse arguments after "run"
const args = process.argv.slice(3);

function printUsage() {
  console.log("Usage: nexus-cli run [options] <prompt>");
  console.log();
  console.log("Launch a Claude Code agent session and report results.");
  console.log();
  console.log("Arguments:");
  console.log("  <prompt>               The prompt to send to the agent");
  console.log();
  console.log("Options:");
  console.log("  --cwd <dir>            Working directory for the agent session");
  console.log("  --model <model>        Model to use (default: claude-sonnet-4-20250514)");
  console.log("  --max-turns <n>        Maximum number of agentic turns");
  console.log("  --permission-mode <m>  Permission mode (default: bypassPermissions)");
  console.log("  -h, --help             Show this help message");
}

let prompt = null;
let cwd = process.cwd();
let model = null;
let maxTurns = null;
let permissionMode = "bypassPermissions";

for (let i = 0; i < args.length; i++) {
  const arg = args[i];
  if (arg === "--help" || arg === "-h") {
    printUsage();
    process.exit(0);
  } else if (arg === "--cwd") {
    cwd = args[++i];
    if (!cwd) {
      process.stderr.write("Error: --cwd requires a directory path\n");
      process.exit(1);
    }
    cwd = path.resolve(cwd);
  } else if (arg === "--model") {
    model = args[++i];
    if (!model) {
      process.stderr.write("Error: --model requires a model name\n");
      process.exit(1);
    }
  } else if (arg === "--max-turns") {
    maxTurns = args[++i];
    if (!maxTurns) {
      process.stderr.write("Error: --max-turns requires a number\n");
      process.exit(1);
    }
  } else if (arg === "--permission-mode") {
    permissionMode = args[++i];
    if (!permissionMode) {
      process.stderr.write("Error: --permission-mode requires a value\n");
      process.exit(1);
    }
  } else if (!arg.startsWith("-")) {
    prompt = arg;
  } else {
    process.stderr.write(`Error: unknown option '${arg}'\n`);
    process.exit(1);
  }
}

if (!prompt) {
  process.stderr.write("Error: a prompt is required\n\n");
  printUsage();
  process.exit(1);
}

// Build claude command args
const claudeArgs = [
  "-p",
  "--output-format", "stream-json",
  "--verbose",
  "--include-partial-messages",
  "--no-session-persistence",
  "--permission-mode", permissionMode,
];

if (model) {
  claudeArgs.push("--model", model);
}
if (maxTurns) {
  claudeArgs.push("--max-turns", maxTurns);
}

claudeArgs.push(prompt);

const startTime = Date.now();

const child = spawn("claude", claudeArgs, {
  cwd,
  stdio: ["ignore", "pipe", "pipe"],
  env: { ...process.env },
});

let buffer = "";
let resultEvent = null;

function processLine(line) {
  if (!line.trim()) return;

  let event;
  try {
    event = JSON.parse(line);
  } catch {
    return;
  }

  if (event.type === "stream_event") {
    const inner = event.event;
    if (inner && inner.type === "content_block_delta" && inner.delta) {
      if (inner.delta.type === "text_delta" && inner.delta.text) {
        process.stderr.write(inner.delta.text);
      }
    } else if (inner && inner.type === "content_block_start" && inner.content_block) {
      if (inner.content_block.type === "tool_use") {
        process.stderr.write(`\n[tool: ${inner.content_block.name}]\n`);
      }
